parameters.jsCode:
// OpenAI Responses API returns data in output[0].content[0].text
let aiText = '';

if ($json.output && Array.isArray($json.output)) {
  // Responses API format
  aiText = $json.output[0].content[0].text;
} else if ($json.text) {
  aiText = $json.text;
} else if ($json.content) {
  aiText = $json.content;
} else {
  aiText = JSON.stringify($json);
}

// Extract JSON from response (handles ```json blocks or raw JSON)
let jsonStr = aiText;
const jsonMatch = aiText.match(/```json\s*([\s\S]*?)```/);
if (jsonMatch) {
  jsonStr = jsonMatch[1];
} else {
  const objMatch = aiText.match(/\{[\s\S]*\}/);
  if (objMatch) jsonStr = objMatch[0];
}

const parsed = JSON.parse(jsonStr.trim());

// Get original form + config data from the Set node
const formData = $('Configure Your Settings').first().json;

return {
  json: {
    leadName: formData['Name'] || '',
    leadEmail: formData['Email'] || '',
    company: formData['Company'] || '',
    budgetRange: formData['Budget Range'] || '',
    projectDescription: formData['Project Description'] || '',
    referralSource: formData['Referral Source'] || '',
    businessName: formData.businessName || '',
    ownerName: formData.ownerName || '',
    ownerEmail: formData.ownerEmail || '',
    calendarLink: formData.calendarLink || '',
    score: parsed.score,
    tier: parsed.tier,
    reasoning: parsed.reasoning,
    emailSubject: parsed.emailSubject,
    emailBody: parsed.emailBody,
    timestamp: new Date().toISOString()
  }
};
